import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XssSecureCode {
    public static void main(String[] args) {
        // Simulating user input being fetched from a form or user input field
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Encode the user input to prevent XSS attacks
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Displaying the properly encoded user input back on the webpage
        System.out.println("Welcome, " + encodedUserInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
